function createRouter(opts?: { local?: boolean, overrides?: ... }) {
  const lightweight = createTrackingProvider('lightweight')
  const standard = createTrackingProvider('standard')
  const local = opts?.local ? createTrackingProvider('local') : undefined
  const router = new ModelRouter({
    providers: { lightweight, standard, local },
    routingOverrides: opts?.overrides,
  })
  return { router, lightweight, standard, local }
}

it('routes classification tasks to lightweight provider', async () => {
  const { router, lightweight, standard } = createRouter()
  ...
})

WHY: A test factory function eliminates ~40 lines of repeated setup and makes the intent of each test case clearer by highlighting what differs (local provider, overrides) rather than what is always the same.

