function makeGradient(w: number, h: number, rgb: (x: number, y: number, w: number, h: number) => [number, number, number]): Buffer {
  const pixels = Buffer.alloc(w * h * 3)
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = (y * w + x) * 3
      const [r, g, b] = rgb(x, y, w, h)
      pixels[i] = r; pixels[i + 1] = g; pixels[i + 2] = b
    }
  }
  return pixels
}

